,\"login\":\"Se connecter\",\"create_universe\":\"Créer mon univers\",\"home\":\"Accueil\",\"members\":\"Membres\",\"messages\":\"Messages\",\"dashboard\":\"Dashboard\",\"register\":\"Inscription\",\"invite\":\"Inviter\",\"premium\":\"Premium\",\"blog\":\"Blog\"},\"landing\":{\"badge\":\"France · Suisse · UK · US\",\"title\":\"Embir : App de Rencontre Gratuite \u0026 Inclusive pour Toutes les Orientations\",\"subtitle\":\"Gratuit au lancement. Profils vérifiés, compatibilité profonde, communauté safe. Rejoins la communauté fondatrice en France, Suisse, Royaume-Uni et États-Unis avant le passage en freemium.\",\"cta_early_access\":\"Demander un accès anticipé\",\"cta_create\":\"Créer mon univers\",\"founder_strip\":\"Accès fondateur · Bienvenue dans mon univers · Compatibilité profonde\",\"card_founder_phase\":\"phase fondateur\",\"card_orientation\":\"Orientation\",\"card_preferences\":\"Préférences\",\"card_compatibility\":\"Compatibilité\",\"card_safety\":\"Sécurité vérifiée\",\"card_join_text\":\"Rejoins la communauté fondatrice avant qu'Embir ne devienne freemium.\",\"markets_title_fr\":\"France\",\"markets_focus_fr\":\"Paris d'abord, puis les grandes villes\",\"markets_title_uk\":\"Royaume-Uni\",\"markets_focus_uk\":\"Londres, Manchester, Birmingham et communautés urbaines\",\"markets_title_us\":\"États-Unis\",\"markets_focus_us\":\"New York, Los Angeles, Miami et demande côtière\",\"markets_title_ch\":\"Suisse\",\"markets_focus_ch\":\"Zurich, Genève, Lausanne et régions frontalières\",\"proof_1_title\":\"Bienvenue dans mon univers\",\"proof_1_text\":\"Embir n'est pas une app à swipe. Les profils sont des univers personnels immersifs où tu t'exprimes pleinement via des visuels, préférences et lifestyle.\",\"proof_2_title\":\"Gratuit au lancement\",\"proof_2_text\":\"L'accès de base est gratuit pour que les premiers membres construisent la communauté avant l'arrivée des options payantes.\",\"proof_3_title\":\"Pour toutes les orientations\",\"proof_3_text\":\"Embir est pour les adultes de toutes orientations, identités et intentions de rencontre, avec des préférences claires dès le premier jour.\",\"proof_4_title\":\"Compatibilité profonde\",\"proof_4_text\":\"La découverte est façonnée par l'orientation, les préférences, l'intention et la compatibilité comportementale plutôt que le volume de swipe.\",\"proof_5_title\":\"Profils vérifiés et sécurité\",\"proof_5_text\":\"Vérification, signalement, modération et contrôles de confidentialité font partie des fondations du produit.\",\"proof_6_title\":\"Futur modèle freemium\",\"proof_6_text\":\"Le futur modèle freemium sera transparent et financera la sécurité, la modération, les apps mobiles et les algorithmes.\",\"founder_cta_tag\":\"Accès fondateur\",\"founder_cta_title\":\"Prêt à créer ton univers ?\",\"founder_cta_text\":\"Gratuit au lancement. Construit pour toutes les orientations. Conçu autour d'univers personnels immersifs, de compatibilité profonde, de profils vérifiés et d'une culture communautaire plus sûre.\",\"founder_cta_button\":\"Demander mon accès anticipé\",\"why_embir_title\":\"Pourquoi Embir change la donne en 2026\",\"why_embir_1_title\":\"Profils vérifiés\",\"why_embir_1_text\":\"Chaque membre peut vérifier son profil par selfie. Le badge vérifié crée un environnement de confiance dès le premier jour — pas de bots, pas de catfish.\",\"why_embir_2_title\":\"Compatibilité réelle\",\"why_embir_2_text\":\"La découverte ne dépend pas du swipe infini mais de l'orientation, des préférences, de l'intention et de la compatibilité. Moins de bruit, plus de connexions qui comptent.\",\"why_embir_3_title\":\"Toutes les orientations\",\"why_embir_3_text\":\"Embir est construit pour les adultes de toutes orientations : hétéro, gay, lesbienne, bi, trans, queer et toute personne qui veut une rencontre plus claire et respectueuse.\",\"why_embir_4_title\":\"Communauté safe\",\"why_embir_4_text\":\"Modération humaine, signalements visibles, zero tolérance harcèlement. La sécurité n'est pas une option — c'est la fondation du produit.\",\"how_works_title\":\"Comment ça marche\",\"how_works_step1_title\":\"1. Crée ton univers\",\"how_works_step1_text\":\"Exprime qui tu es via ton profil immersif : orientation, préférences, lifestyle, intentions. Pas de cases rigides, pas de champs inutiles.\",\"how_works_step2_title\":\"2. Découvre des profils compatibles\",\"how_works_step2_text\":\"La découverte est guidée par la compatibilité réelle, pas seulement la distance. Les profils vérifiés apparaissent en premier.\",\"how_works_step3_title\":\"3. Connecte en confiance\",\"how_works_step3_text\":\"Messagerie gratuite, profils vérifiés, communauté respectueuse. Tu contrôles qui peut te contacter et comment.\",\"faq_home_title\":\"Questions fréquentes\",\"faq_home_q1\":\"Embir est-il vraiment gratuit ?\",\"faq_home_a1\":\"Oui. Embir est gratuit pendant toute la phase de lancement. Les fonctions essentielles — profil, découverte, messages, compatibilité — sont accessibles sans frais. Le futur modèle freemium sera transparent et financera la sécurité, la modération et les applications mobiles.\",\"faq_home_q2\":\"Embir est-il seulement pour une orientation ?\",\"faq_home_a2\":\"Non. Embir est construit pour les personnes majeures de toutes orientations : hétéro, gay, lesbienne, bi, trans, queer. L'orientation et les préférences sont paramétrables dès l'inscription, sans être enfermé dans une case.\",\"faq_home_q3\":\"Comment Embir limite les faux profils ?\",\"faq_home_a3\":\"La vérification par selfie, la modération humaine, les signalements et une conception qui privilégie la qualité de la communauté plutôt que le volume artificiel. Chaque signalement est examiné par une vraie personne.\",\"faq_home_q4\":\"Quelle est la différence avec Tinder ou Bumble ?\",\"faq_home_a4\":\"Embir mise sur la compatibilité profonde et les profils vérifiés plutôt que le swipe infini. Pas d'options essentielles bloquées derrière un abonnement dès le départ. Une approche centrée sur la confiance, la transparence et l'inclusivité réelle.\",\"faq_home_q5\":\"Dans quels pays Embir est-il disponible ?\",\"faq_home_a5\":\"Embir est lancé en France, en Suisse, au Royaume-Uni et aux États-Unis. La plateforme est disponible en français et en anglais. D'autres pays suivront après la phase de lancement.\",\"trust_title\":\"Nos engagements sécurité \u0026 inclusivité\",\"trust_1_title\":\"Modération humaine\",\"trust_1_text\":\"Chaque signalement est examiné par une équipe réelle, pas un algorithme. Le contexte compte et les décisions sont prises avec discernement.\",\"trust_2_title\":\"Zero tolérance harcèlement\",\"trust_2_text\":\"Le harcèlement, les discours de haine et les comportements abusifs entraînent un bannissement immédiat et définitif. La communauté est plus importante que la croissance.\",\"trust_3_title\":\"Vérification des profils\",\"trust_3_text\":\"La vérification par selfie est disponible dès le premier jour. Les profils vérifiés sont clairement identifiés pour que tu saches à qui tu parles.\",\"trust_4_title\":\"Contrôle de tes données\",\"trust_4_text\":\"Tu contrôles qui peut voir ton profil, te contacter et interagir avec toi. La confidentialité est intégrée au produit, pas ajoutée après coup.\"},\"auth\":{\"login\":\"Connexion\",\"register\":\"Inscription\",\"login_tab\":\"Connexion\",\"register_tab\":\"Inscription\",\"email\":\"Email\",\"password\":\"Mot de passe\",\"loginBtn\":\"Se connecter\",\"registerBtn\":\"S'inscrire\",\"noAccount\":\"Pas encore de compte ?\",\"hasAccount\":\"Déjà un compte ?\",\"close\":\"Fermer\",\"welcome_back\":\"Ravi de te revoir\",\"join_embir\":\"Rejoins Embir\"},\"sidebar\":{\"discover\":\"Découvrir\",\"universe\":\"Univers\",\"matches\":\"Matchs\",\"messages\":\"Messages\",\"events\":\"Événements\",\"creator\":\"Studio Créateur\",\"notifications\":\"Notifications\",\"settings\":\"Réglages\"},\"footer\":{\"tagline\":\"Plateforme de rencontre internationale pour toutes les orientation